For anyone still needing a solution, you can hook into the Popper event and modify the tooltip contents yourself and update the contents manually. Prerequisite: create all your tooltips using `data-bs-title=""` like `<span data-bs-toggle="tooltip" data-bs-title="my tooltip title"></span>`:

```js
// Initialize all tooltips.
new window.bootstrap.Tooltip(document.body, {
    selector: '[data-bs-toggle~="tooltip"]',
    container: 'body',
    // @see https://popper.js.org/docs/v2/modifiers/
    popperConfig: function(defaultBsPopperConfig) {
        defaultBsPopperConfig.modifiers.push({
            name: 'FixDynamicTitles',
            enabled: true,
            phase: 'beforeRead',
            fn({state}) {
                // Fix for dynamic titles using `data-bs-title`.
                let title = state.elements.reference.dataset.bsTitle;
                if(title) {
                    state.elements.popper.querySelector('.tooltip-inner').innerHTML = title;
                }
            }
        });
        return defaultBsPopperConfig;
    }
});
```

It is quite dirty but I couldn't find another way to do this, neither using `window.bootstrap.Tooltip.getOrCreateInstance()` or Popper related functions.

